<script setup lang="ts">
import {
addDays,
addMonths,
endOfWeek,
isSameMonth,
isSameYear,
startOfWeek,
subDays,
subMonths,
} from "date-fns";
import { ref } from "vue";

import ChevronLeft from "~/components/icons/ChevronLeft/index.vue";
import ChevronRight from "~/components/icons/ChevronRight/index.vue";
import CalendarMonth from "../CalendarMonth/index.vue";
import CalendarWeek from "../CalendarWeek/index.vue";
import Combobox from "../Combobox/index.vue";
import IconButton from "../IconButton/index.vue";
import OutlinedButton from "../OutlinedButton/index.vue";

const props = defineProps({
  modelValue: {
    type: Date,
    default: new Date(),
    required: true,
  },
  variant: {
    type: String as () => "sm" | "lg",
    default: "lg",
  },
  events: {
    type: Array as () => any[],
    default: [],
  },
  isClickable: {
    type: Boolean,
    default: false,
  },
  isHasChangeMode: {
    type: Boolean,
    default: true,
  },
  currentMonthYear: {
    type: Object as () => { month: number; year: number } | null,
    default: null,
  },
  isLoading: {
    type: Boolean,
    default: false,
  },
  color: {
    type: String as () =>  'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'primary'
  }
});

const emit = defineEmits([
  "update:model-value",
  "on-click-more",
  "on-click-event",
  "on-change-month-year",
]);

const now = new Date();
const currentMonth = ref<number>(now.getMonth());
const currentYear = ref<number>(now.getFullYear());
const selectedCalendarMode = ref<"WEEK" | "MONTH" | "YEAR">("MONTH");

const monthNames = [
  "January",
  "February",
  "March",
  "April",
  "May",
  "June",
  "July",
  "August",
  "September",
  "October",
  "November",
  "December",
];
const calendarModes = ["Month", "Week"];

const formattedMonthYear = computed(() => {
  let monthYear = "";

  if (selectedCalendarMode.value === "WEEK") {
    const startDay = startOfWeek(props.modelValue);
    const endDay = endOfWeek(props.modelValue);
    const sameMonth = isSameMonth(startDay, endDay);
    const sameYear = isSameYear(startDay, endDay);

    monthYear = `${startDay.getDate()} ${sameMonth ? "" : monthNames[startDay.getMonth()]} ${sameYear ? "" : startDay.getFullYear()} - ${endDay.getDate()} ${monthNames[endDay.getMonth()]} ${endDay.getFullYear()}`;
  } else if (selectedCalendarMode.value === "MONTH") {
    monthYear = `${monthNames[currentMonth.value]} ${currentYear.value}`;
  }

  return monthYear;
});

watch(
  () => props.modelValue,
  (date: Date) => {
    currentMonth.value = date.getMonth();
    currentYear.value = date.getFullYear();
  }
);

watch(
  () => props.currentMonthYear,
  (value: { month: number; year: number } | null) => {
    if (value) {
      currentMonth.value = value.month;
      currentYear.value = value.year;
    }
  }
);

watch([currentMonth, currentYear], (currentValue) => {
  emit("on-change-month-year", {
    month: currentValue[0],
    year: currentValue[1],
  });
});

function changeWeek(type: "NEXT" | "PREV") {
  const newDate =
    type === "NEXT"
      ? addDays(props.modelValue, 7)
      : subDays(props.modelValue, 7);

  emit("update:model-value", newDate);
}

function changeMonth(type: "NEXT" | "PREV") {
  const currentDate = new Date(currentYear.value, currentMonth.value, 1);
  const newDate =
    type === "NEXT" ? addMonths(currentDate, 1) : subMonths(currentDate, 1);

  currentMonth.value = newDate.getMonth();
  currentYear.value = newDate.getFullYear();
}

function onClickChange(type: "NEXT" | "PREV") {
  switch (selectedCalendarMode.value) {
    case "WEEK":
      changeWeek(type);
      break;
    case "MONTH":
      changeMonth(type);
      break;
  }
}

const setToday = () => {
  const today = new Date();
  currentMonth.value = today.getMonth();
  currentYear.value = today.getFullYear();
  emit("update:model-value", today);
};
</script>

<template>
  <div class="calendar">
    <div
      class="calendar-header flex justify-between items-center p-4"
      :class="variant === 'lg' ? 'border-b' : ''"
    >
      <div class="flex items-center space-x-4 flex-1">
        <slot name="action-button" />

        <div v-if="props.isHasChangeMode" class="flex space-x-1">
          <IconButton
            class="!w-8 !h-8 !border-none"
            @on-click="onClickChange('PREV')"
          >
            <template #icon>
              <ChevronLeft size="24" class="stroke-gray-900" />
            </template>
          </IconButton>
          <IconButton
            class="!w-8 !h-8 !border-none"
            @on-click="onClickChange('NEXT')"
          >
            <template #icon>
              <ChevronRight size="24" class="stroke-gray-900" />
            </template>
          </IconButton>
        </div>

        <p class="flex-1" :class="variant === 'lg' ? 'text-3xl' : ''">
          {{ formattedMonthYear }}
        </p>
      </div>

      <div class="flex flex-1 items-center justify-end space-x-4">
        <Combobox
          v-if="props.isHasChangeMode"
          v-model="selectedCalendarMode"
          id-trigger="selectMode"
          id-target="modes"
          :color="color"
          plain
          :is-searchable="false"
          placeholder="Select Mode"
          :items="
            calendarModes.map((mode) => ({
              text: mode,
              value: mode.toUpperCase(),
            }))
          "
        />

        <div v-if="variant === 'lg'" class="flex space-x-4">
          <OutlinedButton
            id="btn-set-today"
            label="Today"
            :color="color"
            @on-click="setToday"
          />
        </div>

        <div v-if="!props.isHasChangeMode" class="flex space-x-1">
          <IconButton
            class="!w-8 !h-8 !border-none"
            @on-click="onClickChange('PREV')"
          >
            <template #icon>
              <ChevronLeft size="20" class="stroke-gray-900" />
            </template>
          </IconButton>
          <IconButton
            class="!w-8 !h-8 !border-none"
            @on-click="onClickChange('NEXT')"
          >
            <template #icon>
              <ChevronRight size="20" class="stroke-gray-900" />
            </template>
          </IconButton>
        </div>
      </div>
    </div>

    <CalendarMonth
      v-if="selectedCalendarMode === 'MONTH'"
      :model-value="props.modelValue"
      :variant="props.variant"
      :current-month="currentMonth"
      :current-year="currentYear"
      :is-clickable="props.isClickable"
      :events="props.events"
      :is-loading="props.isLoading"
      :color="color"
      @on-click-more="emit('on-click-more', $event)"
      @on-click-event="emit('on-click-event', $event)"
      @update:model-value="emit('update:model-value', $event)"
    />

    <CalendarWeek
      v-else-if="selectedCalendarMode === 'WEEK'"
      :model-value="props.modelValue"
      :events="props.events"
          :color="color"
      @on-click-event="emit('on-click-event', $event)"
    >
    </CalendarWeek>
  </div>
</template>

<style scoped>
.calendar-header {
  @apply flex justify-between items-center p-4;
}
</style>
